function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const dist = Array(m).fill(0).map(() => Array(n).fill(Infinity));
    dist[0][0] = 0;

    const dirs = [[0, 1], [1, 0]]; // right, down

    // Dijkstra's algorithm with a priority queue
    const pq = [[0, 0, 0, 0]]; // [cost, row, col, usedTransports]

    while (pq.length > 0) {
        const [cost, row, col, used] = pq.shift() as [number, number, number, number];

        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        if (used >= k) {
            // No more transports allowed
            for (const [dr, dc] of dirs) {
                const r = row + dr;
                const c = col + dc;
                if (r >= 0 && r < m && c >= 0 && c < n) {
                    const newCost = cost + grid[r][c];
                    if (newCost < dist[r][c]) {
                        dist[r][c] = newCost;
                        pq.push([newCost, r, c, used]);
                    }
                }
            }
            continue;
        }

        // Regular move (right or down)
        for (const [dr, dc] of dirs) {
            const r = row + dr;
            const c = col + dc;
            if (r >= 0 && r < m && c >= 0 && c < n) {
                const newCost = cost + grid[r][c];
                if (newCost < dist[r][c]) {
                    dist[r][c] = newCost;
                    pq.push([newCost, r, c, used]);
                }
            }
        }

        // Transport move
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (grid[i][j] <= grid[row][col] && i !== row || j !== col) {
                    if (cost < dist[i][j]) {
                        dist[i][j] = cost;
                        pq.push([cost, i, j, used + 1]);
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}

