from typing import List
import heapq

def solve(grid: List[List[int]], k: int) -> int:
    m, n = len(grid), len(grid[0])
    dist = [[float('inf')] * n for _ in range(m)]
    dist[0][0] = 0

    dirs = [(0, 1), (1, 0)]  # right, down

    # Priority queue: [cost, row, col, usedTransports]
    pq = [(0, 0, 0, 0)]

    while pq:
        cost, row, col, used = heapq.heappop(pq)

        if row == m - 1 and col == n - 1:
            return cost

        if used >= k:
            # No more transports allowed
            for dr, dc in dirs:
                r, c = row + dr, col + dc
                if 0 <= r < m and 0 <= c < n:
                    new_cost = cost + grid[r][c]
                    if new_cost < dist[r][c]:
                        dist[r][c] = new_cost
                        heapq.heappush(pq, (new_cost, r, c, used))
            continue

        # Regular move (right or down)
        for dr, dc in dirs:
            r, c = row + dr, col + dc
            if 0 <= r < m and 0 <= c < n:
                new_cost = cost + grid[r][c]
                if new_cost < dist[r][c]:
                    dist[r][c] = new_cost
                    heapq.heappush(pq, (new_cost, r, c, used))

        # Transport move
        for i in range(m):
            for j in range(n):
                if grid[i][j] <= grid[row][col] and (i != row or j != col):
                    if cost < dist[i][j]:
                        dist[i][j] = cost
                        heapq.heappush(pq, (cost, i, j, used + 1))

    return dist[m - 1][n - 1]
